// Lista RSS feedów branżowych
const feeds = [
  { url: 'https://techcrunch.com/category/artificial-intelligence/feed/', source: 'TechCrunch AI' },
  { url: 'https://venturebeat.com/category/ai/feed/', source: 'VentureBeat AI' },
  { url: 'https://www.wired.com/feed/category/artificial-intelligence/latest/rss', source: 'Wired AI' },
  { url: 'https://www.technologyreview.com/feed/', source: 'MIT Tech Review' },
  { url: 'https://openai.com/news/rss/', source: 'OpenAI News' },
  { url: 'https://www.anthropic.com/news/rss', source: 'Anthropic News' }
];

return feeds.map(f => ({ json: f }));

// Parsowanie RSS XML i ekstrakcja artykułów
const items = [];

for (const item of $input.all()) {
  try {
    const xml = item.json.data || item.json.body || '';
    const source = item.json.source || 'Unknown';

    // Prosta ekstrakcja tytułów i opisów z RSS
    const titleMatches = [...xml.matchAll(/<item[^>]*>[\s\S]*?<title[^>]*><!\[CDATA\[([^\]]+)\]\]><\/title>[\s\S]*?<\/item>/g)];
    const simpleTitles = [...xml.matchAll(/<title>([^<]{10,200})<\/title>/g)];
    const descriptions = [...xml.matchAll(/<description><!\[CDATA\[([^\]]{50,1000})\]\]><\/description>/g)];
    const links = [...xml.matchAll(/<link>([^<]+)<\/link>/g)];

    const titles = titleMatches.length > 0 
      ? titleMatches.map(m => m[1])
      : simpleTitles.slice(1, 6).map(m => m[1]); // pomijamy pierwszy (tytuł kanału)

    for (let i = 0; i < Math.min(titles.length, 3); i++) {
      items.push({
        json: {
          source,
          title: titles[i] || '',
          description: descriptions[i]?.[1] || '',
          link: links[i + 1]?.[1] || ''
        }
      });
    }
  } catch (e) {
    // ignorujemy błędy parsowania
  }
}

// Zwracamy max 15 artykułów (po ~2-3 z każdego feedu)
return items.slice(0, 15);

// Zbierz wszystkie artykuły w jeden string do analizy przez AI
const articles = $input.all().map((item, i) => {
  const { source, title, description } = item.json;
  return `${i + 1}. [${source}] ${title}\n   ${description || '(brak opisu)'}`.trim();
}).join('\n\n');

return [{ json: { articles_digest: articles } }];

// Wyciągnij i sparsuj JSON z odpowiedzi Gemini
const response = $input.first().json;
const rawText = response.candidates?.[0]?.content?.parts?.[0]?.text || '';

// Usuń ewentualne markdown code blocks
const cleanText = rawText.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();

let article;
try {
  article = JSON.parse(cleanText);
} catch (e) {
  throw new Error('AI nie zwróciło poprawnego JSON: ' + rawText.substring(0, 200));
}

// Walidacja pól
if (!article.title || !article.slug || !article.content) {
  throw new Error('Brakuje wymaganych pól w odpowiedzi AI.');
}

// Normalizuj slug
article.slug = article.slug
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

return [{ json: article }];

// Połącz artykuł z URL zdjęcia
const article = $('Parsuj odpowiedź AI').first().json;
const unsplashData = $input.first().json;

const photo = unsplashData.results?.[0];
const imageUrl = photo?.urls?.regular || photo?.urls?.small || null;

// Przygotuj payload dla webhooka /api/blog/publish
return [{
  json: {
    slug: article.slug,
    title: article.title,
    content: article.content,
    excerpt: article.excerpt || null,
    cover_image: imageUrl,
    author: 'Zautomatyzujemy',
    tags: article.tags || [],
    published_at: new Date().toISOString()
  }
}];

// Log sukcesu
const result = $input.first().json;
const article = $('Przygotuj payload').first().json;

console.log(`✅ Opublikowano artykuł: "${article.title}"`);
console.log(`URL: ${result.url || '/blog/' + article.slug}`);

return [{ json: { success: true, title: article.title, url: result.url } }];
